import {useVideoConfig, useCurrentFrame} from 'remotion';

export const MyVideo: React.FC<{
  title: string;
}> = ({title}) => {
  const {fps, durationInFrames, width, height} = useVideoConfig();
  const frame = useCurrentFrame();

  // 简单的淡入动画
  const opacity = Math.min(1, frame / 30);

  // 文字滑动效果
  const translateY = Math.max(0, 100 - frame * 2);

  return (
    <div
      style={{
        flex: 1,
        backgroundColor: '#1a1a2e',
        justifyContent: 'center',
        alignItems: 'center',
        display: 'flex',
        fontFamily: 'Noto Sans CJK SC, sans-serif',
      }}
    >
      <div
        style={{
          color: '#fff',
          fontSize: 80,
          fontWeight: 'bold',
          textAlign: 'center',
          opacity,
          transform: `translateY(${translateY}px)`,
        }}
      >
        {title}
      </div>
      <div
        style={{
          position: 'absolute',
          bottom: 100,
          color: '#eee',
          fontSize: 30,
          opacity: opacity * 0.8,
        }}
      >
        Powered by Remotion 🎬
      </div>
    </div>
  );
};

import {useVideoConfig, useCurrentFrame, Audio, interpolate, Easing, staticFile} from 'remotion';

// 基于Whisper真实时间戳的字幕数据
type Subtitle = {
  start: number;
  end: number;
  text: string;
  scene: number;
};

const subtitles: Subtitle[] = [
  {start: 0.00, end: 1.74, text: "每天晚上充到100%？", scene: 1},
  {start: 1.74, end: 5.74, text: "你的电池，正在被这个习惯毁掉", scene: 1},
  {start: 5.74, end: 9.68, text: "一年不到，电池健康掉到80%？", scene: 2},
  {start: 9.68, end: 12.72, text: "问题可能不是手机，是你充电的方式", scene: 2},
  {start: 12.72, end: 17.12, text: "锂电池最怕的，是长期高压和深度放电", scene: 3},
  {start: 17.12, end: 22.50, text: "苹果官方说了：最佳区间是20%到80%", scene: 3},
  {start: 22.50, end: 26.44, text: "100%满电？电池像被绷紧的橡皮筋", scene: 4},
  {start: 26.44, end: 31.08, text: "用到0%关机？等于让电池饿到晕厥", scene: 4},
  {start: 31.08, end: 34.58, text: "这两种极端，都在缩短电池寿命", scene: 4},
  {start: 34.58, end: 39.54, text: "正确的做法很简单：随用随充，别低于20%", scene: 5},
  {start: 39.54, end: 44.96, text: "睡前充到80%就停，现在的快充，早上十分钟就能补满", scene: 5},
  {start: 44.96, end: 50.18, text: "你平时是随充党，还是必须100%才安心？评论区站个队", scene: 6},
];

// 中间大字文案
const centerTexts = [
  {start: 0, end: 6, text: "充到100% = 毁电池", sub: "HOOK"},
  {start: 6, end: 13, text: "一年掉到80%", sub: "电池健康"},
  {start: 13, end: 22, text: "最佳区间 20%-80%", sub: "苹果官方"},
  {start: 22, end: 31, text: "100% vs 0%", sub: "两种伤害"},
  {start: 31, end: 45, text: "随用随充 + 80%原则", sub: "正确做法"},
  {start: 45, end: 51, text: "你是什么党？", sub: "互动"},
];

export const VideoV2: React.FC = () => {
  const {fps, durationInFrames} = useVideoConfig();
  const frame = useCurrentFrame();
  const currentTime = frame / fps;

  // 当前字幕
  const currentSubtitle = subtitles.find(s => currentTime >= s.start && currentTime <= s.end);
  const currentScene = currentSubtitle?.scene || 1;

  // 当前中间文案
  const currentCenter = centerTexts.find(c => currentTime >= c.start && currentTime <= c.end);

  // 场景切换进度 (0-1)
  const getSceneProgress = (sceneNum: number) => {
    const sceneSubs = subtitles.filter(s => s.scene === sceneNum);
    if (sceneSubs.length === 0) return 0;
    const sceneStart = sceneSubs[0].start;
    const sceneEnd = sceneSubs[sceneSubs.length - 1].end;
    if (currentTime < sceneStart) return 0;
    if (currentTime > sceneEnd) return 1;
    return (currentTime - sceneStart) / (sceneEnd - sceneStart);
  };

  const sceneProgress = getSceneProgress(currentScene);

  // 动画函数
  const fadeIn = (delay: number = 0) => {
    const t = Math.max(0, Math.min(1, (currentTime - delay) * 2));
    return interpolate(t, [0, 1], [0, 1], {easing: Easing.out(Easing.ease)});
  };

  const scaleIn = (delay: number = 0) => {
    const t = Math.max(0, Math.min(1, (currentTime - delay) * 1.5));
    return interpolate(t, [0, 1], [0.8, 1], {easing: Easing.elastic(1.2)});
  };

  const slideUp = (delay: number = 0) => {
    const t = Math.max(0, Math.min(1, (currentTime - delay) * 2));
    return interpolate(t, [0, 1], [50, 0], {easing: Easing.out(Easing.ease)});
  };

  // 场景背景色
  const getBgGradient = () => {
    switch(currentScene) {
      case 1: return 'linear-gradient(180deg, #1a0a0a 0%, #2d1b1b 50%, #1a0a0a 100%)'; // 深红警示
      case 2: return 'linear-gradient(180deg, #0a0a1a 0%, #1b1b2d 50%, #0a0a1a 100%)'; // 深蓝
      case 3: return 'linear-gradient(180deg, #0a1a0a 0%, #1b2d1b 50%, #0a1a0a 100%)'; // 深绿（安全）
      case 4: return 'linear-gradient(180deg, #1a0a0a 0%, #2d1b1b 50%, #0a0a1a 100%)'; // 红蓝对比
      case 5: return 'linear-gradient(180deg, #0a1a2d 0%, #1b3d5d 50%, #0a1a2d 100%)'; // 科技蓝
      case 6: return 'linear-gradient(180deg, #1a1a2e 0%, #2d2d4a 50%, #1a1a2e 100%)'; // 紫灰互动
      default: return 'linear-gradient(180deg, #1a1a2e 0%, #16213e 100%)';
    }
  };

  // 中间文案颜色
  const getCenterColor = () => {
    switch(currentScene) {
      case 1: return '#ff4444'; // 红色警示
      case 2: return '#ff8844'; // 橙色
      case 3: return '#44ff88'; // 绿色
      case 4: return '#ffaa44'; // 橙黄
      case 5: return '#44aaff'; // 蓝色
      case 6: return '#ff66aa'; // 粉色
      default: return '#ffffff';
    }
  };

  return (
    <div style={{
      width: 1080,
      height: 1920,
      background: getBgGradient(),
      position: 'relative',
      overflow: 'hidden',
      fontFamily: '"Noto Sans CJK SC", "PingFang SC", "Microsoft YaHei", sans-serif',
    }}>

      {/* ========== 场景1: 开头钩子 ========== */}
      {currentScene === 1 && (
        <>
          {/* 电池图标动画 */}
          <div style={{
            position: 'absolute',
            top: 400,
            left: '50%',
            transform: `translateX(-50%) scale(${scaleIn(0)})`,
            width: 300,
            height: 500,
            border: '12px solid #ff4444',
            borderRadius: 40,
            opacity: fadeIn(0),
          }}>
            <div style={{
              position: 'absolute',
              top: -40,
              left: '50%',
              transform: 'translateX(-50%)',
              width: 100,
              height: 30,
              background: '#ff4444',
              borderRadius: '15px 15px 0 0',
            }} />
            <div style={{
              position: 'absolute',
              bottom: 20,
              left: 20,
              right: 20,
              height: '90%',
              background: 'linear-gradient(180deg, #ff4444 0%, #ff6666 100%)',
              borderRadius: 20,
              animation: 'pulse 1s ease-in-out infinite',
            }} />

            <div style={{
              position: 'absolute',
              top: '50%',
              left: '50%',
              transform: 'translate(-50%, -50%)',
              fontSize: 80,
              fontWeight: 'bold',
              color: '#fff',
            }}>100%</div>
          </div>

          {/* 警示符号 */}
          <div style={{
            position: 'absolute',
            top: 200,
            right: 150,
            fontSize: 120,
            color: '#ff4444',
            opacity: fadeIn(0.5),
            transform: `translateY(${slideUp(0.5)}px)`,
          }}>⚠️</div>
        </>
      )}

      {/* ========== 场景2: 痛点数字 ========== */}
      {currentScene === 2 && (
        <>
          {/* 电池健康度显示 */}
          <div style={{
            position: 'absolute',
            top: 450,
            left: '50%',
            transform: 'translateX(-50%)',
            textAlign: 'center',
          }}>
            <div style={{
              fontSize: 200,
              fontWeight: 'bold',
              color: '#ff8844',
              opacity: fadeIn(0),
              transform: `translateY(${interpolate(sceneProgress, [0, 0.5], [0, 30])}px)`,
            }}>80%</div>

            <div style={{
              fontSize: 48,
              color: '#ffaa66',
              marginTop: 30,
              opacity: fadeIn(0.3),
            }}>电池健康度 ↓</div>

            {/* 下降箭头动画 */}
            <div style={{
              fontSize: 100,
              color: '#ff4444',
              marginTop: 20,
              opacity: interpolate(sceneProgress, [0.3, 0.7], [0, 1]),
              transform: `translateY(${interpolate(sceneProgress, [0.3, 0.7], [-20, 20])}px)`,
            }}>↓</div>
          </div>
        </>
      )}

      {/* ========== 场景3: 官方背书 ========== */}
      {currentScene === 3 && (
        <>
          {/* 苹果风格图标 */}
          <div style={{
            position: 'absolute',
            top: 350,
            left: '50%',
            transform: `translateX(-50%) scale(${scaleIn(0)})`,
            width: 200,
            height: 200,
            background: 'linear-gradient(135deg, #444 0%, #222 100%)',
            borderRadius: 40,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            opacity: fadeIn(0),
          }}>
            <div style={{fontSize: 120, color: '#fff'}}>🍎</div>
          </div>

          {/* 最佳区间可视化 */}
          <div style={{
            position: 'absolute',
            top: 650,
            left: '50%',
            transform: 'translateX(-50%)',
            width: 800,
            height: 100,
            background: 'linear-gradient(90deg, #ff4444 0%, #ffaa44 20%, #44ff88 20%, #44ff88 80%, #ffaa44 80%, #ff4444 100%)',
            borderRadius: 50,
            opacity: fadeIn(0.5),
          }}>
            <div style={{
              position: 'absolute',
              left: '20%',
              top: -60,
              fontSize: 48,
              fontWeight: 'bold',
              color: '#44ff88',
            }}>20%</div>

            <div style={{
              position: 'absolute',
              right: '20%',
              top: -60,
              fontSize: 48,
              fontWeight: 'bold',
              color: '#44ff88',
            }}>80%</div>

            <div style={{
              position: 'absolute',
              left: '50%',
              top: '50%',
              transform: 'translate(-50%, -50%)',
              fontSize: 36,
              fontWeight: 'bold',
              color: '#004400',
            }}>✓ 最佳区间</div>
          </div>

          {/* 危险区标注 */}
          <div style={{
            position: 'absolute',
            top: 800,
            left: 100,
            fontSize: 32,
            color: '#ff6666',
            opacity: fadeIn(0.8),
          }}>⚠️ 危险</div>

          <div style={{
            position: 'absolute',
            top: 800,
            right: 100,
            fontSize: 32,
            color: '#ff6666',
            opacity: fadeIn(0.8),
          }}>危险 ⚠️</div>
        </>
      )}

      {/* ========== 场景4: 对比伤害 ========== */}
      {currentScene === 4 && (
        <>
          {/* 左半部分 - 100%满电 */}
          <div style={{
            position: 'absolute',
            left: 0,
            top: 300,
            width: 540,
            height: 1000,
            background: 'linear-gradient(180deg, #3d1b1b 0%, #2d1515 100%)',
            borderRight: '4px solid #ff4444',
            opacity: fadeIn(0),
            transform: `translateX(${interpolate(sceneProgress, [0, 0.3], [-100, 0])}px)`,
          }}>
            <div style={{
              textAlign: 'center',
              paddingTop: 100,
            }}>
              <div style={{fontSize: 80, marginBottom: 30}}>🔋</div>
              <div style={{fontSize: 60, fontWeight: 'bold', color: '#ff4444'}}>100%</div>
              <div style={{fontSize: 36, color: '#ffaa88', marginTop: 30}}>满电高压</div>
              <div style={{fontSize: 100, marginTop: 50}}>🪢</div>
              <div style={{fontSize: 32, color: '#ff8888', marginTop: 30, padding: '0 40px'}}>像绷紧的橡皮筋</div>
            </div>
          </div>

          {/* 右半部分 - 0%空电 */}
          <div style={{
            position: 'absolute',
            right: 0,
            top: 300,
            width: 540,
            height: 1000,
            background: 'linear-gradient(180deg, #1b1b3d 0%, #15152d 100%)',
            opacity: fadeIn(0.2),
            transform: `translateX(${interpolate(sceneProgress, [0, 0.3], [100, 0])}px)`,
          }}>
            <div style={{
              textAlign: 'center',
              paddingTop: 100,
            }}>
              <div style={{fontSize: 80, marginBottom: 30}}>🪫</div>
              <div style={{fontSize: 60, fontWeight: 'bold', color: '#4488ff'}}>0%</div>
              <div style={{fontSize: 36, color: '#88aaff', marginTop: 30}}>深度放电</div>
              <div style={{fontSize: 100, marginTop: 50}}>😵</div>
              <div style={{fontSize: 32, color: '#88aaff', marginTop: 30, padding: '0 40px'}}>饿到晕厥</div>
            </div>
          </div>

          {/* VS标识 */}
          <div style={{
            position: 'absolute',
            top: 750,
            left: '50%',
            transform: 'translateX(-50%)',
            fontSize: 48,
            fontWeight: 'bold',
            color: '#ffaa44',
            background: '#1a1a1a',
            padding: '10px 30px',
            borderRadius: 30,
            border: '4px solid #ffaa44',
            opacity: fadeIn(0.4),
          }}>VS</div>
        </>
      )}

      {/* ========== 场景5: 解决方案 ========== */}
      {currentScene === 5 && (
        <>
          {/* 步骤卡片 */}
          <div style={{
            position: 'absolute',
            top: 350,
            left: '50%',
            transform: 'translateX(-50%)',
            width: 900,
          }}>
            {/* 步骤1 */}
            <div style={{
              background: 'linear-gradient(135deg, #2a5a8a 0%, #1a4a7a 100%)',
              borderRadius: 30,
              padding: 40,
              marginBottom: 30,
              opacity: interpolate(sceneProgress, [0, 0.2], [0, 1]),
              transform: `translateX(${interpolate(sceneProgress, [0, 0.2], [100, 0])}px)`,
              display: 'flex',
              alignItems: 'center',
            }}>
              <div style={{
                width: 80,
                height: 80,
                background: '#44aaff',
                borderRadius: '50%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 40,
                fontWeight: 'bold',
                color: '#fff',
                marginRight: 30,
              }}>1</div>
              <div style={{fontSize: 44, color: '#fff', fontWeight: 'bold'}}>随用随充</div>
            </div>

            {/* 步骤2 */}
            <div style={{
              background: 'linear-gradient(135deg, #2a8a5a 0%, #1a7a4a 100%)',
              borderRadius: 30,
              padding: 40,
              marginBottom: 30,
              opacity: interpolate(sceneProgress, [0.2, 0.4], [0, 1]),
              transform: `translateX(${interpolate(sceneProgress, [0.2, 0.4], [100, 0])}px)`,
              display: 'flex',
              alignItems: 'center',
            }}>
              <div style={{
                width: 80,
                height: 80,
                background: '#44ff88',
                borderRadius: '50%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 40,
                fontWeight: 'bold',
                color: '#1a4a3a',
                marginRight: 30,
              }}>2</div>
              <div style={{fontSize: 44, color: '#fff', fontWeight: 'bold'}}>别低于20%</div>
            </div>

            {/* 步骤3 */}
            <div style={{
              background: 'linear-gradient(135deg, #8a5a2a 0%, #7a4a1a 100%)',
              borderRadius: 30,
              padding: 40,
              opacity: interpolate(sceneProgress, [0.4, 0.6], [0, 1]),
              transform: `translateX(${interpolate(sceneProgress, [0.4, 0.6], [100, 0])}px)`,
              display: 'flex',
              alignItems: 'center',
            }}>
              <div style={{
                width: 80,
                height: 80,
                background: '#ffaa44',
                borderRadius: '50%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 40,
                fontWeight: 'bold',
                color: '#4a3a1a',
                marginRight: 30,
              }}>3</div>
              <div style={{fontSize: 44, color: '#fff', fontWeight: 'bold'}}>睡前80%就停 ✓</div>
            </div>
          </div>

          {/* 时间轴装饰 */}
          <div style={{
            position: 'absolute',
            top: 1150,
            left: '50%',
            transform: 'translateX(-50%)',
            width: 700,
            height: 10,
            background: 'linear-gradient(90deg, #44aaff 0%, #44ff88 50%, #ffaa44 100%)',
            borderRadius: 5,
            opacity: fadeIn(0.6),
          }} />
        </>
      )}

      {/* ========== 场景6: 结尾CTA ========== */}
      {currentScene === 6 && (
        <>
          {/* 投票样式 */}
          <div style={{
            position: 'absolute',
            top: 400,
            left: '50%',
            transform: 'translateX(-50%)',
            width: 900,
          }}>
            <div style={{
              fontSize: 48,
              color: '#ffaaee',
              textAlign: 'center',
              marginBottom: 60,
              opacity: fadeIn(0),
            }}>你是什么充电党？</div>

            {/* 选项1 */}
            <div style={{
              background: 'linear-gradient(135deg, #2a8a5a 0%, #1a7a4a 100%)',
              borderRadius: 30,
              padding: 50,
              marginBottom: 40,
              opacity: interpolate(sceneProgress, [0, 0.3], [0, 1]),
              transform: `scale(${interpolate(sceneProgress, [0, 0.3], [0.9, 1])})`,
              textAlign: 'center',
              border: '4px solid #44ff88',
            }}>
              <div style={{fontSize: 60, marginBottom: 20}}>🔋</div>
              <div style={{fontSize: 48, color: '#fff', fontWeight: 'bold'}}>随充党</div>
              <div style={{fontSize: 32, color: '#88ffaa', marginTop: 15}}>随用随充，不纠结</div>
            </div>

            {/* 选项2 */}
            <div style={{
              background: 'linear-gradient(135deg, #8a2a5a 0%, #7a1a4a 100%)',
              borderRadius: 30,
              padding: 50,
              opacity: interpolate(sceneProgress, [0.2, 0.5], [0, 1]),
              transform: `scale(${interpolate(sceneProgress, [0.2, 0.5], [0.9, 1])})`,
              textAlign: 'center',
              border: '4px solid #ff66aa',
            }}>
              <div style={{fontSize: 60, marginBottom: 20}}>🔌</div>
              <div style={{fontSize: 48, color: '#fff', fontWeight: 'bold'}}>100%党</div>
              <div style={{fontSize: 32, color: '#ff88aa', marginTop: 15}}>必须充满才安心</div>
            </div>
          </div>

          {/* 引导关注 */}
          <div style={{
            position: 'absolute',
            bottom: 300,
            left: '50%',
            transform: 'translateX(-50%)',
            fontSize: 36,
            color: '#aaa',
            textAlign: 'center',
            opacity: fadeIn(0.6),
          }}>
            双击 ❤️ 关注，获取更多数码冷知识
          </div>
        </>
      )}

      {/* ========== 中间大字文案（所有场景通用） ========== */}
      {currentCenter && (
        <>
          {/* 主文案 */}
          <div style={{
            position: 'absolute',
            top: 200,
            left: '50%',
            transform: `translateX(-50%)`,
            textAlign: 'center',
            width: 900,
          }}>
            <div style={{
              fontSize: currentScene === 1 ? 90 : 80,
              fontWeight: 'bold',
              color: getCenterColor(),
              textShadow: '0 4px 20px rgba(0,0,0,0.5)',
              opacity: fadeIn(0),
              lineHeight: 1.3,
            }}>
              {currentCenter.text}
            </div>

            <div style={{
              fontSize: 32,
              color: '#888',
              marginTop: 20,
              opacity: fadeIn(0.2),
            }}>
              {currentCenter.sub}
            </div>
          </div>
        </>
      )}

      {/* ========== 底部字幕（所有场景通用） ========== */}
      <div style={{
        position: 'absolute',
        bottom: 150,
        left: 60,
        right: 60,
        minHeight: 120,
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
      }}>
        {currentSubtitle && (
          <div style={{
            background: 'rgba(0, 0, 0, 0.7)',
            padding: '20px 40px',
            borderRadius: 16,
            maxWidth: '100%',
          }}>
            <div style={{
              fontSize: 44,
              color: '#fff',
              fontWeight: 'bold',
