import {useVideoConfig, useCurrentFrame, Audio, interpolate, Easing, staticFile, Img, spring} from 'remotion';

// 场景数据结构
type Scene = {
  id: number;
  title: string;
  subtitle: string;
  image: string;
  duration: number; // 秒
  bgColor: string;
  accentColor: string;
  narration: string;
  quotes: { text: string; time: number }[];
};

const scenes: Scene[] = [
  {
    id: 1,
    title: "第1幕 · 雪地弃子",
    subtitle: "公元前140年 · 雁门关外",
    image: "weiqing/scene1.jpg",
    duration: 50,
    bgColor: "#0a1520",
    accentColor: "#4a9eff",
    narration: "他是郑青，父亲是汉朝雁门郡一个小吏。匈奴来时，父亲丢下他和母亲，独自逃命。母亲病死后，他被卖到了长安。",
    quotes: [
      { text: "他是郑青", time: 5 },
      { text: "匈奴来时，父亲丢下他和母亲", time: 15 },
      { text: "独自逃命", time: 25 },
    ],
  },
  {
    id: 2,
    title: "第2幕 · 侯府为奴",
    subtitle: "长安城郊 · 平阳侯府",
    image: "weiqing/scene2.jpg",
    duration: 50,
    bgColor: "#15100a",
    accentColor: "#ff9944",
    narration: "八年后，他成了平阳侯府最下等的奴隶。没有名字，主人叫他'小青'。没人知道他是郑季的亲生儿子，也没人在乎。",
    quotes: [
      { text: "八年之后", time: 5 },
      { text: "最下等的奴隶", time: 15 },
      { text: "没人知道他的名字", time: 28 },
    ],
  },
  {
    id: 3,
    title: "第3幕 · 姐姐重逢",
    subtitle: "平阳公主府 · 后院",
    image: "weiqing/scene3.jpg",
    duration: 50,
    bgColor: "#0a1510",
    accentColor: "#ff88aa",
    narration: "姐姐卫子夫在平阳公主府做歌姬，是他唯一的光。那天黄昏，他偷偷跑来见姐姐，带了半个馒头。",
    quotes: [
      { text: "姐姐是他唯一的光", time: 5 },
      { text: "姐，我会带你离开这里", time: 20 },
      { text: "匈奴人来了", time: 35 },
    ],
  },
  {
    id: 4,
    title: "第4幕 · 决定参军",
    subtitle: "长安城 · 征兵处",
    image: "weiqing/scene4.jpg",
    duration: 50,
    bgColor: "#150a0a",
    accentColor: "#ff4444",
    narration: "边关急报，匈奴单于率十万大军南侵。朝廷在全国征召良家子从军。卫青知道——参军，是他唯一的路。",
    quotes: [
      { text: "匈奴犯边", time: 5 },
      { text: "十万大军南侵", time: 15 },
      { text: "参军，是我唯一的路", time: 30 },
    ],
  },
  {
    id: 5,
    title: "第5幕 · 离别之夜",
    subtitle: "平阳侯府 · 后门",
    image: "weiqing/scene5.jpg",
    duration: 50,
    bgColor: "#080a15",
    accentColor: "#88aaff",
    narration: "月光下，卫青背着简单的包袱。姐姐追出来，泪流满面，将汗巾塞入他手中。他微微一笑——那笑容带着寒光。",
    quotes: [
      { text: "姐，我会回来的", time: 8 },
      { text: "你若死了……我烧给你", time: 20 },
      { text: "我还有账没算完", time: 35 },
    ],
  },
  {
    id: 6,
    title: "第6幕 · 踏上征途",
    subtitle: "长安城外 · 官道",
    image: "weiqing/scene6.jpg",
    duration: 50,
    bgColor: "#101508",
    accentColor: "#ffdd44",
    narration: "建元年间，匈奴连年犯边。汉武帝下诏全国，征召良家子从军。无数年轻人踏上北去的道路。没有人知道，其中一个奴隶，将成为改变历史的那个人。",
    quotes: [
      { text: "天将降大任于斯人", time: 10 },
      { text: "必先苦其心志", time: 22 },
      { text: "终成一代战神", time: 40 },
    ],
  },
];

// 计算总时长
const TOTAL_DURATION = scenes.reduce((sum, s) => sum + s.duration, 0);

// 获取当前场景
const getCurrentScene = (frame: number, fps: number) => {
  let acc = 0;
  for (const scene of scenes) {
    acc += scene.duration * fps;
    if (frame < acc) {
      return {
        scene,
        sceneStart: acc - scene.duration * fps,
        sceneProgress: (frame - (acc - scene.duration * fps)) / (scene.duration * fps),
      };
    }
  }
  return {
    scene: scenes[scenes.length - 1],
    sceneStart: 0,
    sceneProgress: 1,
  };
};

// 动画函数
const fadeIn = (progress: number) => interpolate(progress, [0, 0.3], [0, 1], {easing: Easing.out(Easing.ease)});
const fadeOut = (progress: number) => interpolate(progress, [0.7, 1], [1, 0], {easing: Easing.in(Easing.ease)});
const slideUp = (progress: number) => interpolate(progress, [0, 0.3], [60, 0], {easing: Easing.out(Easing.ease)});
const zoomIn = (progress: number) => interpolate(progress, [0, 0.5], [1, 1.15], {easing: Easing.out(Easing.ease)});

// 字幕组件
const Subtitle: React.FC<{ text: string; opacity: number }> = ({text, opacity}) => (
  <div style={{
    position: 'absolute',
    bottom: 180,
    left: 0,
    right: 0,
    display: 'flex',
    justifyContent: 'center',
    pointerEvents: 'none',
  }}>
    <div style={{
      background: 'rgba(0,0,0,0.75)',
      padding: '24px 48px',
      borderRadius: 16,
      maxWidth: '90%',
      opacity,
    }}>
      <span style={{
        fontSize: 42,
        fontWeight: 'bold',
        color: '#fff',
        fontFamily: '"Noto Sans CJK SC", "PingFang SC", "Microsoft YaHei", sans-serif',
        textShadow: '0 2px 8px rgba(0,0,0,0.8)',
        lineHeight: 1.4,
      }}>
        {text}
      </span>
    </div>
  </div>
);

// 场景标题组件
const SceneTitle: React.FC<{ title: string; subtitle: string; opacity: number; progress: number }> = ({title, subtitle, opacity, progress}) => (
  <div style={{
    position: 'absolute',
    top: 160,
    left: 60,
    right: 60,
    opacity,
    transform: `translateY(${slideUp(progress)}px)`,
  }}>
    <div style={{
      fontSize: 28,
      color: '#888',
      fontFamily: '"Noto Sans CJK SC", sans-serif',
      marginBottom: 12,
      letterSpacing: 4,
    }}>
      {subtitle}
    </div>
    <div style={{
      fontSize: 52,
      fontWeight: 'bold',
      color: '#fff',
      fontFamily: '"Noto Sans CJK SC", "PingFang SC", "Microsoft YaHei", sans-serif',
      textShadow: '0 4px 20px rgba(0,0,0,0.8)',
    }}>
      {title}
    </div>
  </div>
);

// 底部导航条
const ProgressBar: React.FC<{ currentFrame: number; fps: number }> = ({currentFrame, fps}) => (
  <div style={{
    position: 'absolute',
    bottom: 60,
    left: 60,
    right: 60,
    display: 'flex',
    gap: 8,
    alignItems: 'center',
  }}>
    {scenes.map((s, i) => {
      const sceneStartFrame = scenes.slice(0, i).reduce((sum, sc) => sum + sc.duration * fps, 0);
      const sceneEndFrame = sceneStartFrame + s.duration * fps;
      const isActive = currentFrame >= sceneStartFrame && currentFrame < sceneEndFrame;
      const progress = isActive ? (currentFrame - sceneStartFrame) / (s.duration * fps) : (isActive ? 1 : 0);
      return (
        <div key={s.id} style={{
          flex: 1,
          height: 6,
          background: 'rgba(255,255,255,0.15)',
          borderRadius: 3,
          overflow: 'hidden',
        }}>
          <div style={{
            height: '100%',
            width: `${Math.min(100, progress * 100)}%`,
            background: isActive ? '#fff' : 'rgba(255,255,255,0.4)',
            borderRadius: 3,
            transition: 'background 0.3s',
          }} />
        </div>
      );
    })}
  </div>
);

// 引言卡片
const QuoteCard: React.FC<{ text: string; opacity: number }> = ({text, opacity}) => (
  <div style={{
    position: 'absolute',
    top: '50%',
    left: '50%',
    transform: 'translate(-50%, -50%)',
    opacity,
    textAlign: 'center',
    padding: '40px 60px',
    background: 'rgba(0,0,0,0.6)',
    borderRadius: 24,
    border: '2px solid rgba(255,255,255,0.15)',
    backdropFilter: 'blur(10px)',
  }}>
    <div style={{
      fontSize: 56,
      fontWeight: 'bold',
      color: '#fff',
      fontFamily: '"Noto Sans CJK SC", "PingFang SC", "Microsoft YaHei", sans-serif',
      textShadow: '0 4px 30px rgba(0,0,0,0.9)',
      lineHeight: 1.3,
    }}>
      {text}
    </div>
  </div>
);

export const WeiQing: React.FC = () => {
  const {fps} = useVideoConfig();
  const frame = useCurrentFrame();
  const currentTime = frame / fps;

  const {scene, sceneStart, sceneProgress} = getCurrentScene(frame, fps);

  // 场景内的局部时间
  const localTime = (frame - sceneStart) / fps;
  const localProgress = sceneProgress;

  // 引言
  const activeQuote = scene.quotes.find(q => Math.abs(localTime - q.time) < 3);
  const quoteOpacity = activeQuote
    ? interpolate(Math.abs(localTime - activeQuote.time), [0, 1.5], [1, 0], {easing: Easing.out(Easing.ease)})
    : 0;

  // 标题透明度
  const titleOpacity = fadeIn(Math.min(1, localProgress * 4)) * fadeOut(Math.max(0, (localProgress - 0.7) * 5));

  // Ken Burns效果 - 缓慢缩放
  const zoomValue = zoomIn(Math.min(localProgress, 0.8));

  // 场景渐变叠加
  const topFade = interpolate(Math.min(1, localProgress * 5), [0, 1], [0.6, 0.2]);
  const bottomFade = interpolate(Math.min(1, localProgress * 5), [0, 1], [0.6, 0.3]);

  return (
    <div style={{
      width: 1080,
      height: 1920,
      backgroundColor: scene.bgColor,
      position: 'relative',
      overflow: 'hidden',
      fontFamily: '"Noto Sans CJK SC", "PingFang SC", "Microsoft YaHei", sans-serif',
    }}>

      {/* ========== 背景图片 ========== */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        transform: `scale(${zoomValue})`,
        transformOrigin: 'center center',
      }}>
        <Img
          src={staticFile(scene.image)}
          style={{
            width: '100%',
            height: '100%',
            objectFit: 'cover',
          }}
        />
      </div>

      {/* 顶部渐变遮罩 */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        height: 400,
        background: `linear-gradient(180deg, ${scene.bgColor} ${topFade * 100}%, transparent 100%)`,
      }} />

      {/* 底部渐变遮罩 */}
      <div style={{
        position: 'absolute',
        bottom: 0,
        left: 0,
        right: 0,
        height: 600,
        background: `linear-gradient(0deg, ${scene.bgColor} ${bottomFade * 100}%, transparent 100%)`,
      }} />

      {/* 中央引言 */}
      {activeQuote && <QuoteCard text={activeQuote.text} opacity={quoteOpacity} />}

      {/* 场景标题 */}
      <SceneTitle
        title={scene.title}
        subtitle={scene.subtitle}
        opacity={titleOpacity}
        progress={localProgress}
      />

      {/* 底部字幕 */}
      {activeQuote ? (
        <Subtitle text={scene.narration} opacity={Math.max(0, quoteOpacity - 0.5)} />
      ) : (
        <Subtitle text={scene.narration} opacity={fadeIn(Math.min(1, (localProgress - 0.1) * 5))} />
      )}

      {/* 进度条 */}
      <ProgressBar currentFrame={frame} fps={fps} />

      {/* 集数标识 */}
      <div style={{
        position: 'absolute',
        top: 60,
        right: 60,
        fontSize: 24,
        color: 'rgba(255,255,255,0.4)',
        fontFamily: '"Noto Sans CJK SC", sans-serif',
        letterSpacing: 2,
      }}>
